/**
 * BrainHub — Knowledge base data layer
 *
 * Uses a pre-built JSON index (generated by scripts/build-brainhub-index.js)
 * for fast, lightweight search without bundling the full markdown content.
 *
 * The JSON contains: title, path, snippet (250 chars), category.
 * Full content is opened directly from source on click.
 */

import brainDocs from './brainhub-index.json'

export function getBrainDocs() {
  return brainDocs
}

export function searchBrainHub(query) {
  if (!query.trim()) return []
  const q = query.toLowerCase()

  return brainDocs
    .map((doc) => {
      let score = 0
      if (doc.title.toLowerCase().includes(q)) score += 15
      if (doc.category.toLowerCase().includes(q)) score += 8
      if (doc.snippet.toLowerCase().includes(q)) {
        let idx = -1
        while ((idx = doc.snippet.toLowerCase().indexOf(q, idx + 1)) !== -1) score += 2
      }
      return { doc, score }
    })
    .filter((r) => r.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, 20)
    .map((r) => r.doc)
}
